import { createField, newLineId, type IField } from '../../../../form-shared';
import type { JournalEntryHeaderKey, JournalEntryHeaderModel } from '../types/journalEntryHeader.types';
import { JOURNAL_ENTRY_DISPLAY_ONLY_KEYS } from '../types/journalEntryHeader.types';
import type { JournalEntryLineModel } from '../types/journalEntryLine.types';
import { emptyJournalEntryLine } from '../types/journalEntryLine.types';

export type JournalEntryLineFieldKey = keyof JournalEntryLineModel;

export interface JournalEntryLineFieldState {
  lineId: string;
  fields: Record<JournalEntryLineFieldKey, IField<string | number>>;
}

export function initJournalHeaderFields(
  model: JournalEntryHeaderModel,
): Record<JournalEntryHeaderKey, IField<string>> {
  const out = {} as Record<JournalEntryHeaderKey, IField<string>>;
  (Object.keys(model) as JournalEntryHeaderKey[]).forEach(key => {
    out[key] = createField(model[key], { displayOnly: JOURNAL_ENTRY_DISPLAY_ONLY_KEYS.includes(key) });
  });
  return out;
}

export function buildJournalLineStatesFromModels(
  models: JournalEntryLineModel[],
): JournalEntryLineFieldState[] {
  if (models.length === 0) {
    return [initJournalLineFields(emptyJournalEntryLine(), newLineId())];
  }
  return models.map(m => initJournalLineFields(m, newLineId()));
}

export function initJournalLineFields(model: JournalEntryLineModel, lineId: string): JournalEntryLineFieldState {
  const fields = {} as Record<JournalEntryLineFieldKey, IField<string | number>>;
  (Object.keys(model) as JournalEntryLineFieldKey[]).forEach(key => {
    fields[key] = createField(model[key]);
  });
  return { lineId, fields };
}

export function journalLineModelFromFields(line: JournalEntryLineFieldState): JournalEntryLineModel {
  const out = {} as JournalEntryLineModel;
  (Object.keys(line.fields) as JournalEntryLineFieldKey[]).forEach(key => {
    out[key] = line.fields[key].value as never;
  });
  return out;
}

export function journalLinesFromState(lines: JournalEntryLineFieldState[]): JournalEntryLineModel[] {
  return lines.map(journalLineModelFromFields);
}

export { newLineId };
